(function () {
  const API_URL = 'https://joaquina-sigma.vercel.app/api/chat';
  const AVATAR = 'data:image/png;base64,';

  const css = `
    #ft-widget-btn {
      position: fixed; bottom: 24px; right: 24px; z-index: 9999;
      width: 72px; height: 72px; border-radius: 50%;
      border: 3px solid #d4a437;
      background: #1E1B2E; cursor: pointer;
      overflow: hidden;
      box-shadow: 0 8px 24px rgba(0,0,0,0.22);
      transition: transform 0.2s; padding: 0;
    }
    #ft-widget-btn:hover { transform: scale(1.05); }
    #ft-widget-btn img { width: 100%; height: 100%; object-fit: cover; display: block; }
    #ft-widget-box {
      position: fixed; bottom: 106px; right: 24px; z-index: 9999;
      width: 340px; max-width: calc(100vw - 32px);
      border-radius: 18px; overflow: hidden;
      box-shadow: 0 12px 40px rgba(0,0,0,0.22);
      display: none; flex-direction: column;
      font-family: Arial, sans-serif; background: #fff;
      max-height: calc(100vh - 140px);
    }
    #ft-widget-box.open { display: flex; }
    #ft-widget-header {
      background: #1E1B2E; padding: 14px 16px;
      display: flex; align-items: center; gap: 12px;
    }
    #ft-widget-header img {
      width: 42px; height: 42px; border-radius: 50%;
      border: 2px solid #d4a437; object-fit: cover;
    }
    #ft-widget-header-info h3 { margin: 0; font-size: 15px; color: #fff; }
    #ft-widget-header-info p {
      margin: 2px 0 0; font-size: 11px; color: rgba(255,255,255,0.7);
      display: flex; align-items: center; gap: 4px;
    }
    #ft-widget-header-info p span {
      width: 6px; height: 6px; border-radius: 50%; background: #22c55e; display: inline-block;
    }
    #ft-widget-close {
      margin-left: auto; background: none; border: none; cursor: pointer;
      color: rgba(255,255,255,0.5); font-size: 22px; line-height: 1; padding: 0 2px;
    }
    #ft-widget-close:hover { color: #fff; }
    #ft-widget-messages {
      flex: 1; height: 320px; min-height: 0; overflow-y: auto; overflow-x: hidden; scroll-behavior: smooth;
      padding: 16px; background: #faf9fc;
      display: flex; flex-direction: column; gap: 8px;
    }
    .ft-msg { display: flex; }
    .ft-msg.user { justify-content: flex-end; }
    .ft-msg.bot  { justify-content: flex-start; }
    .ft-bubble {
      max-width: 82%; padding: 10px 13px; font-size: 13px; line-height: 1.5;
      border-radius: 14px; word-wrap: break-word; overflow-wrap: break-word; min-width: 0;
    }
    .ft-msg.user .ft-bubble {
      background: #1E1B2E; color: #fff;
      border-radius: 14px 14px 4px 14px;
    }
    .ft-msg.bot .ft-bubble {
      background: #ece8f7; color: #222;
      border-radius: 14px 14px 14px 4px;
    }
    #ft-widget-input-row {
      display: flex; gap: 8px; padding: 10px 12px;
      border-top: 1px solid #eee; background: #fff;
    }
    #ft-widget-input {
      flex: 1; border: 1px solid #ddd; border-radius: 12px;
      padding: 10px 12px; font-size: 13px; outline: none;
    }
    #ft-widget-input:focus { border-color: #1E1B2E; }
    #ft-widget-send {
      background: #d4a437; color: #1E1B2E; border: none;
      border-radius: 12px; padding: 10px 14px;
      font-size: 13px; font-weight: bold; cursor: pointer;
    }
    #ft-widget-send:hover { background: #c9962a; }
    #ft-widget-footer {
      text-align: center; padding: 6px;
      font-size: 10px; color: #bbb; background: #fff;
      border-top: 1px solid #f0f0ee;
    }
    #ft-widget-footer a { color: #d4a437; text-decoration: none; }
  `;

  const style = document.createElement('style');
  style.textContent = css;
  document.head.appendChild(style);

  document.body.insertAdjacentHTML('beforeend', `
    <button id="ft-widget-btn" title="Fale com a Joaquina">
      <img src="${AVATAR}" alt="Joaquina">
    </button>
    <div id="ft-widget-box">
      <div id="ft-widget-header">
        <img src="${AVATAR}" alt="Joaquina">
        <div id="ft-widget-header-info">
          <h3>Joaquina</h3>
          <p><span></span> Assistente Floripa Ticket</p>
        </div>
        <button id="ft-widget-close">&#215;</button>
      </div>
      <div id="ft-widget-messages">
        <div class="ft-msg bot">
          <div class="ft-bubble">Olá! Sou a <strong>Joaquina</strong>, assistente virtual do Floripa Ticket. Como posso ajudar? 😊</div>
        </div>
      </div>
      <div id="ft-widget-input-row">
        <input id="ft-widget-input" placeholder="Digite sua mensagem..." autocomplete="off">
        <button id="ft-widget-send">Enviar</button>
      </div>
      <div id="ft-widget-footer">
        <a href="https://floripaticket.com.br" target="_blank">floripaticket.com.br</a>
      </div>
    </div>
  `);

  const btn   = document.getElementById('ft-widget-btn');
  const box   = document.getElementById('ft-widget-box');
  const msgs  = document.getElementById('ft-widget-messages');
  const input = document.getElementById('ft-widget-input');
  const send  = document.getElementById('ft-widget-send');
  const close = document.getElementById('ft-widget-close');

  let history = [];
  let busy = false;

  btn.addEventListener('click', () => { box.classList.toggle('open'); if (box.classList.contains('open')) input.focus(); });
  close.addEventListener('click', () => box.classList.remove('open'));
  send.addEventListener('click', sendMsg);
  input.addEventListener('keydown', e => { if (e.key === 'Enter') sendMsg(); });

  function addMsg(role, text) {
    const div = document.createElement('div');
    div.className = 'ft-msg ' + (role === 'user' ? 'user' : 'bot');
    const bubble = document.createElement('div');
    bubble.className = 'ft-bubble';
    bubble.innerHTML = role === 'user' ? esc(text) : mdToHtml(text);
    div.appendChild(bubble);
    msgs.appendChild(div);
    msgs.scrollTop = msgs.scrollHeight;
    return div;
  }

  function esc(t) { return t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

  function mdToHtml(t) {
    t = esc(t);
    t = t.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    t = t.split('\n').map(l => {
      if (l.match(/^[-•] /)) return '<li>' + l.replace(/^[-•] /, '') + '</li>';
      if (l.match(/^\d+\. /)) return '<li>' + l.replace(/^\d+\. /, '') + '</li>';
      return l ? '<p style="margin:3px 0">' + l + '</p>' : '';
    }).join('');
    t = t.replace(/(<li>[\s\S]*?<\/li>)+/g, '<ul style="margin:4px 0;padding-left:16px">$&</ul>');
    return t;
  }

  async function sendMsg() {
    const text = input.value.trim();
    if (!text || busy) return;
    input.value = '';
    addMsg('user', text);
    history.push({ role: 'user', content: text });
    busy = true; send.disabled = true;

    const typing = addMsg('bot', '');
    typing.querySelector('.ft-bubble').innerHTML = '<em style="color:#999">Joaquina está digitando...</em>';

    try {
      const res = await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: history }),
      });
      const data = await res.json();
      const reply = data.reply || 'Desculpe, não consegui processar. Tente novamente.';
      history.push({ role: 'assistant', content: reply });
      typing.querySelector('.ft-bubble').innerHTML = mdToHtml(reply);
    } catch {
      typing.querySelector('.ft-bubble').textContent = 'Problema de conexão. Tente novamente.';
    }

    msgs.scrollTop = msgs.scrollHeight;
    busy = false; send.disabled = false; input.focus();
  }
})();
